import{_ as s,o as a,c as t,O as o}from"./chunks/framework.bdcb0ee1.js";const u=JSON.parse('{"title":"Custom Layout Templates","description":"","frontmatter":{},"headers":[],"relativePath":"theme/custom-templates.md","filePath":"theme/custom-templates.md","lastUpdated":null}'),n={name:"theme/custom-templates.md"},l=o(`<h1 id="custom-layout-templates" tabindex="-1">Custom Layout Templates <a class="header-anchor" href="#custom-layout-templates" aria-label="Permalink to &quot;Custom Layout Templates&quot;">​</a></h1><p>Custom Layout Templates let you completely redesign how <strong>forum rows</strong>, <strong>topic rows</strong>, <strong>replies</strong>, and <strong>categories</strong> appear on your board using simple HTML with template variables. This gives you JCINK/InvisionFree-level customization without modifying any source code.</p><h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><p>ForumSpark provides <strong>four template regions</strong> that can be customized:</p><table><thead><tr><th>Template</th><th>Where It Appears</th><th>Description</th></tr></thead><tbody><tr><td><strong>Forum Row</strong></td><td>Board index page</td><td>Each forum listing within a category</td></tr><tr><td><strong>Topic Row</strong></td><td>Forum view page</td><td>Each topic listing within a forum</td></tr><tr><td><strong>Reply</strong></td><td>Topic view page</td><td>Each post/reply in a thread</td></tr><tr><td><strong>Category</strong></td><td>Board index page</td><td>The wrapper around each category and its forums</td></tr></tbody></table><p>Templates are managed in <strong>Admin Panel &gt; Board Templates</strong> or through the <strong>Theme Editor</strong> sidebar (Templates tab).</p><hr><h2 id="template-syntax" tabindex="-1">Template Syntax <a class="header-anchor" href="#template-syntax" aria-label="Permalink to &quot;Template Syntax&quot;">​</a></h2><p>Templates use a Mustache-style syntax with HTML:</p><h3 id="variables" tabindex="-1">Variables <a class="header-anchor" href="#variables" aria-label="Permalink to &quot;Variables&quot;">​</a></h3><p>Insert dynamic data using double curly braces:</p><div class="language-html"><button title="Copy Code" class="copy"></button><span class="lang">html</span><pre class="shiki material-theme-palenight"><code><span class="line"><span style="color:#A6ACCD;">{{ forum.name }}</span></span>
<span class="line"><span style="color:#A6ACCD;">{{ user.username }}</span></span>
<span class="line"><span style="color:#A6ACCD;">{{ topic.title }}</span></span></code></pre></div><p>All variables are <strong>HTML-escaped</strong> by default for security.</p><h3 id="dot-notation" tabindex="-1">Dot Notation <a class="header-anchor" href="#dot-notation" aria-label="Permalink to &quot;Dot Notation&quot;">​</a></h3><p>Access nested properties:</p><div class="language-html"><button title="Copy Code" class="copy"></button><span class="lang">html</span><pre class="shiki material-theme-palenight"><code><span class="line"><span style="color:#A6ACCD;">{{ forum.last_post.author }}</span></span>
<span class="line"><span style="color:#A6ACCD;">{{ topic.author.username }}</span></span></code></pre></div><h3 id="conditionals" tabindex="-1">Conditionals <a class="header-anchor" href="#conditionals" aria-label="Permalink to &quot;Conditionals&quot;">​</a></h3><p>Show content conditionally:</p><div class="language-html"><button title="Copy Code" class="copy"></button><span class="lang">html</span><pre class="shiki material-theme-palenight"><code><span class="line"><span style="color:#A6ACCD;">{{#if forum.is_redirect}}</span></span>
<span class="line"><span style="color:#A6ACCD;">    </span><span style="color:#89DDFF;">&lt;</span><span style="color:#F07178;">span</span><span style="color:#89DDFF;">&gt;</span><span style="color:#A6ACCD;">Redirect</span><span style="color:#89DDFF;">&lt;/</span><span style="color:#F07178;">span</span><span style="color:#89DDFF;">&gt;</span></span>
<span class="line"><span style="color:#A6ACCD;">{{/if}}</span></span>
<span class="line"></span>
<span class="line"><span style="color:#A6ACCD;">{{#unless topic.is_locked}}</span></span>
<span class="line"><span style="color:#A6ACCD;">    </span><span style="color:#89DDFF;">&lt;</span><span style="color:#F07178;">a</span><span style="color:#89DDFF;"> </span><span style="color:#C792EA;">href</span><span style="color:#89DDFF;">=</span><span style="color:#89DDFF;">&quot;</span><span style="color:#C3E88D;">{{ topic.url }}</span><span style="color:#89DDFF;">&quot;</span><span style="color:#89DDFF;">&gt;</span><span style="color:#A6ACCD;">Reply</span><span style="color:#89DDFF;">&lt;/</span><span style="color:#F07178;">a</span><span style="color:#89DDFF;">&gt;</span></span>
<span class="line"><span style="color:#A6ACCD;">{{/unless}}</span></span></code></pre></div><h3 id="loops" tabindex="-1">Loops <a class="header-anchor" href="#loops" aria-label="Permalink to &quot;Loops&quot;">​</a></h3><p>Iterate over arrays:</p><div class="language-html"><button title="Copy Code" class="copy"></button><span class="lang">html</span><pre class="shiki material-theme-palenight"><code><span class="line"><span style="color:#A6ACCD;">{{#each forum.subforums}}</span></span>
<span class="line"><span style="color:#A6ACCD;">    </span><span style="color:#89DDFF;">&lt;</span><span style="color:#F07178;">a</span><span style="color:#89DDFF;"> </span><span style="color:#C792EA;">href</span><span style="color:#89DDFF;">=</span><span style="color:#89DDFF;">&quot;</span><span style="color:#C3E88D;">{{ this.url }}</span><span style="color:#89DDFF;">&quot;</span><span style="color:#89DDFF;">&gt;</span><span style="color:#A6ACCD;">{{ this.name }}</span><span style="color:#89DDFF;">&lt;/</span><span style="color:#F07178;">a</span><span style="color:#89DDFF;">&gt;</span></span>
<span class="line"><span style="color:#A6ACCD;">{{/each}}</span></span></code></pre></div><p>Inside a loop, use <code>{{ this.property }}</code> to access the current item and <code>{{ @index }}</code> for the zero-based loop index.</p><h3 id="truthy-falsy-rules" tabindex="-1">Truthy/Falsy Rules <a class="header-anchor" href="#truthy-falsy-rules" aria-label="Permalink to &quot;Truthy/Falsy Rules&quot;">​</a></h3><ul><li><strong>Falsy:</strong> <code>null</code>, empty string <code>&quot;&quot;</code>, <code>false</code>, empty array <code>[]</code></li><li><strong>Truthy:</strong> Everything else (including <code>0</code> and <code>&quot;0&quot;</code>)</li></ul><hr><h2 id="forum-row-template" tabindex="-1">Forum Row Template <a class="header-anchor" href="#forum-row-template" aria-label="Permalink to &quot;Forum Row Template&quot;">​</a></h2><p>Customizes each forum&#39;s appearance on the board index.</p><h3 id="available-variables" tabindex="-1">Available Variables <a class="header-anchor" href="#available-variables" aria-label="Permalink to &quot;Available Variables&quot;">​</a></h3><table><thead><tr><th>Variable</th><th>Type</th><th>Description</th></tr></thead><tbody><tr><td><code>forum.id</code></td><td>number</td><td>Forum ID</td></tr><tr><td><code>forum.name</code></td><td>string</td><td>Forum name</td></tr><tr><td><code>forum.description</code></td><td>string</td><td>Forum description (formatted HTML)</td></tr><tr><td><code>forum.url</code></td><td>string</td><td>Forum URL</td></tr><tr><td><code>forum.is_read</code></td><td>boolean</td><td>Whether the forum has been read</td></tr><tr><td><code>forum.is_redirect</code></td><td>boolean</td><td>Whether this is a redirect forum</td></tr><tr><td><code>forum.topics_count</code></td><td>string</td><td>Formatted topic count (e.g., &quot;1,234&quot;)</td></tr><tr><td><code>forum.replies_count</code></td><td>string</td><td>Formatted reply count</td></tr><tr><td><code>forum.viewers_count</code></td><td>string</td><td>Formatted viewer count</td></tr><tr><td><code>forum.redirect_hits</code></td><td>string</td><td>Formatted redirect hit count</td></tr><tr><td><code>forum.subforums</code></td><td>array</td><td>List of child subforums</td></tr><tr><td><code>forum.subforums[].name</code></td><td>string</td><td>Subforum name</td></tr><tr><td><code>forum.subforums[].url</code></td><td>string</td><td>Subforum URL</td></tr><tr><td><code>forum.last_post</code></td><td>object</td><td>Last post info (empty if no posts)</td></tr><tr><td><code>forum.last_post.title</code></td><td>string</td><td>Last post topic title</td></tr><tr><td><code>forum.last_post.url</code></td><td>string</td><td>Last post URL</td></tr><tr><td><code>forum.last_post.author</code></td><td>string</td><td>Last post author&#39;s username</td></tr><tr><td><code>forum.last_post.avatar_url</code></td><td>string</td><td>Last post author&#39;s avatar URL</td></tr><tr><td><code>forum.last_post.date</code></td><td>string</td><td>Human-readable date (e.g., &quot;2 hours ago&quot;)</td></tr></tbody></table><h3 id="example-forum-row" tabindex="-1">Example: Forum Row <a class="header-anchor" href="#example-forum-row" aria-label="Permalink to &quot;Example: Forum Row&quot;">​</a></h3><div class="language-html"><button title="Copy Code" class="copy"></button><span class="lang">html</span><pre class="shiki material-theme-palenight"><code><span class="line"><span style="color:#89DDFF;">&lt;</span><span style="color:#F07178;">div</span><span style="color:#89DDFF;"> </span><span style="color:#C792EA;">style</span><span style="color:#89DDFF;">=</span><span style="color:#89DDFF;">&quot;</span><span style="color:#C3E88D;">display: flex; padding: 1rem; border-bottom: 1px solid #e2e8f0;</span><span style="color:#89DDFF;">&quot;</span><span style="color:#89DDFF;">&gt;</span></span>
<span class="line"><span style="color:#A6ACCD;">    </span><span style="color:#89DDFF;">&lt;</span><span style="color:#F07178;">div</span><span style="color:#89DDFF;"> </span><span style="color:#C792EA;">style</span><span style="color:#89DDFF;">=</span><span style="color:#89DDFF;">&quot;</span><span style="color:#C3E88D;">flex: 1;</span><span style="color:#89DDFF;">&quot;</span><span style="color:#89DDFF;">&gt;</span></span>
<span class="line"><span style="color:#A6ACCD;">        </span><span style="color:#89DDFF;">&lt;</span><span style="color:#F07178;">a</span><span style="color:#89DDFF;"> </span><span style="color:#C792EA;">href</span><span style="color:#89DDFF;">=</span><span style="color:#89DDFF;">&quot;</span><span style="color:#C3E88D;">{{ forum.url }}</span><span style="color:#89DDFF;">&quot;</span><span style="color:#89DDFF;"> </span><span style="color:#C792EA;">style</span><span style="color:#89DDFF;">=</span><span style="color:#89DDFF;">&quot;</span><span style="color:#C3E88D;">font-weight: bold; font-size: 1.1rem;</span><span style="color:#89DDFF;">&quot;</span><span style="color:#89DDFF;">&gt;</span></span>
<span class="line"><span style="color:#A6ACCD;">            {{ forum.name }}</span></span>
<span class="line"><span style="color:#A6ACCD;">        </span><span style="color:#89DDFF;">&lt;/</span><span style="color:#F07178;">a</span><span style="color:#89DDFF;">&gt;</span></span>
<span class="line"><span style="color:#A6ACCD;">        {{#if forum.description}}</span></span>
<span class="line"><span style="color:#A6ACCD;">            </span><span style="color:#89DDFF;">&lt;</span><span style="color:#F07178;">div</span><span style="color:#89DDFF;"> </span><span style="color:#C792EA;">style</span><span style="color:#89DDFF;">=</span><span style="color:#89DDFF;">&quot;</span><span style="color:#C3E88D;">color: #64748b; font-size: 0.875rem; margin-top: 0.25rem;</span><span style="color:#89DDFF;">&quot;</span><span style="color:#89DDFF;">&gt;</span></span>
<span class="line"><span style="color:#A6ACCD;">                {{ forum.description }}</span></span>
<span class="line"><span style="color:#A6ACCD;">            </span><span style="color:#89DDFF;">&lt;/</span><span style="color:#F07178;">div</span><span style="color:#89DDFF;">&gt;</span></span>
<span class="line"><span style="color:#A6ACCD;">        {{/if}}</span></span>
<span class="line"><span style="color:#A6ACCD;">        {{#if forum.subforums}}</span></span>
<span class="line"><span style="color:#A6ACCD;">            </span><span style="color:#89DDFF;">&lt;</span><span style="color:#F07178;">div</span><span style="color:#89DDFF;"> </span><span style="color:#C792EA;">style</span><span style="color:#89DDFF;">=</span><span style="color:#89DDFF;">&quot;</span><span style="color:#C3E88D;">margin-top: 0.5rem; font-size: 0.8rem; color: #94a3b8;</span><span style="color:#89DDFF;">&quot;</span><span style="color:#89DDFF;">&gt;</span></span>
<span class="line"><span style="color:#A6ACCD;">                Subforums:</span></span>
<span class="line"><span style="color:#A6ACCD;">                {{#each forum.subforums}}</span></span>
<span class="line"><span style="color:#A6ACCD;">                    </span><span style="color:#89DDFF;">&lt;</span><span style="color:#F07178;">a</span><span style="color:#89DDFF;"> </span><span style="color:#C792EA;">href</span><span style="color:#89DDFF;">=</span><span style="color:#89DDFF;">&quot;</span><span style="color:#C3E88D;">{{ this.url }}</span><span style="color:#89DDFF;">&quot;</span><span style="color:#89DDFF;">&gt;</span><span style="color:#A6ACCD;">{{ this.name }}</span><span style="color:#89DDFF;">&lt;/</span><span style="color:#F07178;">a</span><span style="color:#89DDFF;">&gt;</span></span>
<span class="line"><span style="color:#A6ACCD;">                {{/each}}</span></span>
<span class="line"><span style="color:#A6ACCD;">            </span><span style="color:#89DDFF;">&lt;/</span><span style="color:#F07178;">div</span><span style="color:#89DDFF;">&gt;</span></span>
<span class="line"><span style="color:#A6ACCD;">        {{/if}}</span></span>
<span class="line"><span style="color:#A6ACCD;">    </span><span style="color:#89DDFF;">&lt;/</span><span style="color:#F07178;">div</span><span style="color:#89DDFF;">&gt;</span></span>
<span class="line"><span style="color:#A6ACCD;">    </span><span style="color:#89DDFF;">&lt;</span><span style="color:#F07178;">div</span><span style="color:#89DDFF;"> </span><span style="color:#C792EA;">style</span><span style="color:#89DDFF;">=</span><span style="color:#89DDFF;">&quot;</span><span style="color:#C3E88D;">text-align: center; width: 100px; font-size: 0.875rem;</span><span style="color:#89DDFF;">&quot;</span><span style="color:#89DDFF;">&gt;</span></span>
<span class="line"><span style="color:#A6ACCD;">        </span><span style="color:#89DDFF;">&lt;</span><span style="color:#F07178;">div</span><span style="color:#89DDFF;">&gt;</span><span style="color:#A6ACCD;">{{ forum.topics_count }} topics</span><span style="color:#89DDFF;">&lt;/</span><span style="color:#F07178;">div</span><span style="color:#89DDFF;">&gt;</span></span>
<span class="line"><span style="color:#A6ACCD;">        </span><span style="color:#89DDFF;">&lt;</span><span style="color:#F07178;">div</span><span style="color:#89DDFF;">&gt;</span><span style="color:#A6ACCD;">{{ forum.replies_count }} replies</span><span style="color:#89DDFF;">&lt;/</span><span style="color:#F07178;">div</span><span style="color:#89DDFF;">&gt;</span></span>
<span class="line"><span style="color:#A6ACCD;">    </span><span style="color:#89DDFF;">&lt;/</span><span style="color:#F07178;">div</span><span style="color:#89DDFF;">&gt;</span></span>
<span class="line"><span style="color:#A6ACCD;">    {{#if forum.last_post}}</span></span>
<span class="line"><span style="color:#A6ACCD;">        </span><span style="color:#89DDFF;">&lt;</span><span style="color:#F07178;">div</span><span style="color:#89DDFF;"> </span><span style="color:#C792EA;">style</span><span style="color:#89DDFF;">=</span><span style="color:#89DDFF;">&quot;</span><span style="color:#C3E88D;">width: 200px; font-size: 0.8rem;</span><span style="color:#89DDFF;">&quot;</span><span style="color:#89DDFF;">&gt;</span></span>
<span class="line"><span style="color:#A6ACCD;">            </span><span style="color:#89DDFF;">&lt;</span><span style="color:#F07178;">a</span><span style="color:#89DDFF;"> </span><span style="color:#C792EA;">href</span><span style="color:#89DDFF;">=</span><span style="color:#89DDFF;">&quot;</span><span style="color:#C3E88D;">{{ forum.last_post.url }}</span><span style="color:#89DDFF;">&quot;</span><span style="color:#89DDFF;">&gt;</span><span style="color:#A6ACCD;">{{ forum.last_post.title }}</span><span style="color:#89DDFF;">&lt;/</span><span style="color:#F07178;">a</span><span style="color:#89DDFF;">&gt;</span></span>
<span class="line"><span style="color:#A6ACCD;">            </span><span style="color:#89DDFF;">&lt;</span><span style="color:#F07178;">div</span><span style="color:#89DDFF;">&gt;</span><span style="color:#A6ACCD;">by {{ forum.last_post.author }}, {{ forum.last_post.date }}</span><span style="color:#89DDFF;">&lt;/</span><span style="color:#F07178;">div</span><span style="color:#89DDFF;">&gt;</span></span>
<span class="line"><span style="color:#A6ACCD;">        </span><span style="color:#89DDFF;">&lt;/</span><span style="color:#F07178;">div</span><span style="color:#89DDFF;">&gt;</span></span>
<span class="line"><span style="color:#A6ACCD;">    {{/if}}</span></span>
<span class="line"><span style="color:#89DDFF;">&lt;/</span><span style="color:#F07178;">div</span><span style="color:#89DDFF;">&gt;</span></span></code></pre></div><hr><h2 id="topic-row-template" tabindex="-1">Topic Row Template <a class="header-anchor" href="#topic-row-template" aria-label="Permalink to &quot;Topic Row Template&quot;">​</a></h2><p>Customizes how each topic appears in the forum view.</p><h3 id="available-variables-1" tabindex="-1">Available Variables <a class="header-anchor" href="#available-variables-1" aria-label="Permalink to &quot;Available Variables&quot;">​</a></h3><table><thead><tr><th>Variable</th><th>Type</th><th>Description</th></tr></thead><tbody><tr><td><code>topic.id</code></td><td>number</td><td>Topic ID</td></tr><tr><td><code>topic.title</code></td><td>string</td><td>Topic title</td></tr><tr><td><code>topic.url</code></td><td>string</td><td>Topic URL</td></tr><tr><td><code>topic.is_read</code></td><td>boolean</td><td>Whether the topic has been read</td></tr><tr><td><code>topic.is_pinned</code></td><td>boolean</td><td>Whether the topic is pinned/sticky</td></tr><tr><td><code>topic.is_locked</code></td><td>boolean</td><td>Whether the topic is locked</td></tr><tr><td><code>topic.replies_count</code></td><td>string</td><td>Formatted reply count</td></tr><tr><td><code>topic.views_count</code></td><td>string</td><td>Formatted view count</td></tr><tr><td><code>topic.created_at</code></td><td>string</td><td>Human-readable date</td></tr><tr><td><code>topic.label</code></td><td>string</td><td>Label name (empty if none)</td></tr><tr><td><code>topic.label_color</code></td><td>string</td><td>Label hex color (empty if none)</td></tr><tr><td><code>topic.author</code></td><td>object</td><td>Topic author info</td></tr><tr><td><code>topic.author.username</code></td><td>string</td><td>Author&#39;s username</td></tr><tr><td><code>topic.author.avatar_url</code></td><td>string</td><td>Author&#39;s avatar URL</td></tr><tr><td><code>topic.author.profile_url</code></td><td>string</td><td>Author&#39;s profile URL</td></tr><tr><td><code>topic.last_post</code></td><td>object</td><td>Last reply info (empty if no replies)</td></tr><tr><td><code>topic.last_post.author</code></td><td>string</td><td>Last replier&#39;s username</td></tr><tr><td><code>topic.last_post.avatar_url</code></td><td>string</td><td>Last replier&#39;s avatar URL</td></tr><tr><td><code>topic.last_post.date</code></td><td>string</td><td>Human-readable date</td></tr></tbody></table><h3 id="example-topic-row" tabindex="-1">Example: Topic Row <a class="header-anchor" href="#example-topic-row" aria-label="Permalink to &quot;Example: Topic Row&quot;">​</a></h3><div class="language-html"><button title="Copy Code" class="copy"></button><span class="lang">html</span><pre class="shiki material-theme-palenight"><code><span class="line"><span style="color:#89DDFF;">&lt;</span><span style="color:#F07178;">div</span><span style="color:#89DDFF;"> </span><span style="color:#C792EA;">style</span><span style="color:#89DDFF;">=</span><span style="color:#89DDFF;">&quot;</span><span style="color:#C3E88D;">display: flex; align-items: center; padding: 0.75rem 1rem; border-bottom: 1px solid #e2e8f0;</span><span style="color:#89DDFF;">&quot;</span><span style="color:#89DDFF;">&gt;</span></span>
<span class="line"><span style="color:#A6ACCD;">    {{#if topic.is_pinned}}</span></span>
<span class="line"><span style="color:#A6ACCD;">        </span><span style="color:#89DDFF;">&lt;</span><span style="color:#F07178;">span</span><span style="color:#89DDFF;"> </span><span style="color:#C792EA;">style</span><span style="color:#89DDFF;">=</span><span style="color:#89DDFF;">&quot;</span><span style="color:#C3E88D;">color: #f59e0b; margin-right: 0.5rem;</span><span style="color:#89DDFF;">&quot;</span><span style="color:#89DDFF;"> </span><span style="color:#C792EA;">title</span><span style="color:#89DDFF;">=</span><span style="color:#89DDFF;">&quot;</span><span style="color:#C3E88D;">Pinned</span><span style="color:#89DDFF;">&quot;</span><span style="color:#89DDFF;">&gt;</span><span style="color:#A6ACCD;">📌</span><span style="color:#89DDFF;">&lt;/</span><span style="color:#F07178;">span</span><span style="color:#89DDFF;">&gt;</span></span>
<span class="line"><span style="color:#A6ACCD;">    {{/if}}</span></span>
<span class="line"><span style="color:#A6ACCD;">    {{#if topic.is_locked}}</span></span>
<span class="line"><span style="color:#A6ACCD;">        </span><span style="color:#89DDFF;">&lt;</span><span style="color:#F07178;">span</span><span style="color:#89DDFF;"> </span><span style="color:#C792EA;">style</span><span style="color:#89DDFF;">=</span><span style="color:#89DDFF;">&quot;</span><span style="color:#C3E88D;">color: #ef4444; margin-right: 0.5rem;</span><span style="color:#89DDFF;">&quot;</span><span style="color:#89DDFF;"> </span><span style="color:#C792EA;">title</span><span style="color:#89DDFF;">=</span><span style="color:#89DDFF;">&quot;</span><span style="color:#C3E88D;">Locked</span><span style="color:#89DDFF;">&quot;</span><span style="color:#89DDFF;">&gt;</span><span style="color:#A6ACCD;">🔒</span><span style="color:#89DDFF;">&lt;/</span><span style="color:#F07178;">span</span><span style="color:#89DDFF;">&gt;</span></span>
<span class="line"><span style="color:#A6ACCD;">    {{/if}}</span></span>
<span class="line"><span style="color:#A6ACCD;">    </span><span style="color:#89DDFF;">&lt;</span><span style="color:#F07178;">div</span><span style="color:#89DDFF;"> </span><span style="color:#C792EA;">style</span><span style="color:#89DDFF;">=</span><span style="color:#89DDFF;">&quot;</span><span style="color:#C3E88D;">flex: 1; min-width: 0;</span><span style="color:#89DDFF;">&quot;</span><span style="color:#89DDFF;">&gt;</span></span>
<span class="line"><span style="color:#A6ACCD;">        {{#if topic.label}}</span></span>
<span class="line"><span style="color:#A6ACCD;">            </span><span style="color:#89DDFF;">&lt;</span><span style="color:#F07178;">span</span><span style="color:#89DDFF;"> </span><span style="color:#C792EA;">style</span><span style="color:#89DDFF;">=</span><span style="color:#89DDFF;">&quot;</span><span style="color:#C3E88D;">background: {{ topic.label_color }}; color: white; padding: 0.125rem 0.5rem; border-radius: 0.25rem; font-size: 0.75rem; margin-right: 0.5rem;</span><span style="color:#89DDFF;">&quot;</span><span style="color:#89DDFF;">&gt;</span></span>
<span class="line"><span style="color:#A6ACCD;">                {{ topic.label }}</span></span>
<span class="line"><span style="color:#A6ACCD;">            </span><span style="color:#89DDFF;">&lt;/</span><span style="color:#F07178;">span</span><span style="color:#89DDFF;">&gt;</span></span>
<span class="line"><span style="color:#A6ACCD;">        {{/if}}</span></span>
<span class="line"><span style="color:#A6ACCD;">        </span><span style="color:#89DDFF;">&lt;</span><span style="color:#F07178;">a</span><span style="color:#89DDFF;"> </span><span style="color:#C792EA;">href</span><span style="color:#89DDFF;">=</span><span style="color:#89DDFF;">&quot;</span><span style="color:#C3E88D;">{{ topic.url }}</span><span style="color:#89DDFF;">&quot;</span><span style="color:#89DDFF;"> </span><span style="color:#C792EA;">style</span><span style="color:#89DDFF;">=</span><span style="color:#89DDFF;">&quot;</span><span style="color:#C3E88D;">font-weight: {{ topic.is_read ? &#39;normal&#39; : &#39;bold&#39; }};</span><span style="color:#89DDFF;">&quot;</span><span style="color:#89DDFF;">&gt;</span></span>
<span class="line"><span style="color:#A6ACCD;">            {{ topic.title }}</span></span>
<span class="line"><span style="color:#A6ACCD;">        </span><span style="color:#89DDFF;">&lt;/</span><span style="color:#F07178;">a</span><span style="color:#89DDFF;">&gt;</span></span>
<span class="line"><span style="color:#A6ACCD;">        </span><span style="color:#89DDFF;">&lt;</span><span style="color:#F07178;">div</span><span style="color:#89DDFF;"> </span><span style="color:#C792EA;">style</span><span style="color:#89DDFF;">=</span><span style="color:#89DDFF;">&quot;</span><span style="color:#C3E88D;">font-size: 0.8rem; color: #64748b; margin-top: 0.25rem;</span><span style="color:#89DDFF;">&quot;</span><span style="color:#89DDFF;">&gt;</span></span>
<span class="line"><span style="color:#A6ACCD;">            by </span><span style="color:#89DDFF;">&lt;</span><span style="color:#F07178;">a</span><span style="color:#89DDFF;"> </span><span style="color:#C792EA;">href</span><span style="color:#89DDFF;">=</span><span style="color:#89DDFF;">&quot;</span><span style="color:#C3E88D;">{{ topic.author.profile_url }}</span><span style="color:#89DDFF;">&quot;</span><span style="color:#89DDFF;">&gt;</span><span style="color:#A6ACCD;">{{ topic.author.username }}</span><span style="color:#89DDFF;">&lt;/</span><span style="color:#F07178;">a</span><span style="color:#89DDFF;">&gt;</span><span style="color:#A6ACCD;">,</span></span>
<span class="line"><span style="color:#A6ACCD;">            {{ topic.created_at }}</span></span>
<span class="line"><span style="color:#A6ACCD;">        </span><span style="color:#89DDFF;">&lt;/</span><span style="color:#F07178;">div</span><span style="color:#89DDFF;">&gt;</span></span>
<span class="line"><span style="color:#A6ACCD;">    </span><span style="color:#89DDFF;">&lt;/</span><span style="color:#F07178;">div</span><span style="color:#89DDFF;">&gt;</span></span>
<span class="line"><span style="color:#A6ACCD;">    </span><span style="color:#89DDFF;">&lt;</span><span style="color:#F07178;">div</span><span style="color:#89DDFF;"> </span><span style="color:#C792EA;">style</span><span style="color:#89DDFF;">=</span><span style="color:#89DDFF;">&quot;</span><span style="color:#C3E88D;">text-align: center; width: 80px; font-size: 0.875rem;</span><span style="color:#89DDFF;">&quot;</span><span style="color:#89DDFF;">&gt;</span></span>
<span class="line"><span style="color:#A6ACCD;">        {{ topic.replies_count }}</span></span>
<span class="line"><span style="color:#A6ACCD;">        </span><span style="color:#89DDFF;">&lt;</span><span style="color:#F07178;">div</span><span style="color:#89DDFF;"> </span><span style="color:#C792EA;">style</span><span style="color:#89DDFF;">=</span><span style="color:#89DDFF;">&quot;</span><span style="color:#C3E88D;">font-size: 0.7rem; color: #94a3b8;</span><span style="color:#89DDFF;">&quot;</span><span style="color:#89DDFF;">&gt;</span><span style="color:#A6ACCD;">replies</span><span style="color:#89DDFF;">&lt;/</span><span style="color:#F07178;">div</span><span style="color:#89DDFF;">&gt;</span></span>
<span class="line"><span style="color:#A6ACCD;">    </span><span style="color:#89DDFF;">&lt;/</span><span style="color:#F07178;">div</span><span style="color:#89DDFF;">&gt;</span></span>
<span class="line"><span style="color:#A6ACCD;">    </span><span style="color:#89DDFF;">&lt;</span><span style="color:#F07178;">div</span><span style="color:#89DDFF;"> </span><span style="color:#C792EA;">style</span><span style="color:#89DDFF;">=</span><span style="color:#89DDFF;">&quot;</span><span style="color:#C3E88D;">text-align: center; width: 80px; font-size: 0.875rem;</span><span style="color:#89DDFF;">&quot;</span><span style="color:#89DDFF;">&gt;</span></span>
<span class="line"><span style="color:#A6ACCD;">        {{ topic.views_count }}</span></span>
<span class="line"><span style="color:#A6ACCD;">        </span><span style="color:#89DDFF;">&lt;</span><span style="color:#F07178;">div</span><span style="color:#89DDFF;"> </span><span style="color:#C792EA;">style</span><span style="color:#89DDFF;">=</span><span style="color:#89DDFF;">&quot;</span><span style="color:#C3E88D;">font-size: 0.7rem; color: #94a3b8;</span><span style="color:#89DDFF;">&quot;</span><span style="color:#89DDFF;">&gt;</span><span style="color:#A6ACCD;">views</span><span style="color:#89DDFF;">&lt;/</span><span style="color:#F07178;">div</span><span style="color:#89DDFF;">&gt;</span></span>
<span class="line"><span style="color:#A6ACCD;">    </span><span style="color:#89DDFF;">&lt;/</span><span style="color:#F07178;">div</span><span style="color:#89DDFF;">&gt;</span></span>
<span class="line"><span style="color:#89DDFF;">&lt;/</span><span style="color:#F07178;">div</span><span style="color:#89DDFF;">&gt;</span></span></code></pre></div><hr><h2 id="reply-template" tabindex="-1">Reply Template <a class="header-anchor" href="#reply-template" aria-label="Permalink to &quot;Reply Template&quot;">​</a></h2><p>Customizes how each post/reply appears in a thread.</p><h3 id="available-variables-2" tabindex="-1">Available Variables <a class="header-anchor" href="#available-variables-2" aria-label="Permalink to &quot;Available Variables&quot;">​</a></h3><p><strong>Reply Variables:</strong></p><table><thead><tr><th>Variable</th><th>Type</th><th>Description</th></tr></thead><tbody><tr><td><code>reply.id</code></td><td>number</td><td>Reply/post ID</td></tr><tr><td><code>reply.number</code></td><td>number</td><td>Position in thread (1, 2, 3...)</td></tr><tr><td><code>reply.content</code></td><td>string</td><td>Formatted post content (HTML)</td></tr><tr><td><code>reply.created_at</code></td><td>string</td><td>Human-readable date</td></tr><tr><td><code>reply.is_op</code></td><td>boolean</td><td>Whether this is the opening post</td></tr><tr><td><code>reply.attachments</code></td><td>array</td><td>Attached files</td></tr><tr><td><code>reply.attachments[].filename</code></td><td>string</td><td>File name</td></tr><tr><td><code>reply.attachments[].url</code></td><td>string</td><td>Download URL</td></tr><tr><td><code>reply.attachments[].size</code></td><td>string</td><td>Formatted file size</td></tr><tr><td><code>reply.attachments[].is_image</code></td><td>boolean</td><td>Whether attachment is an image</td></tr></tbody></table><p><strong>User Variables (available in reply templates):</strong></p><table><thead><tr><th>Variable</th><th>Type</th><th>Description</th></tr></thead><tbody><tr><td><code>user.username</code></td><td>string</td><td>Post author&#39;s display name</td></tr><tr><td><code>user.avatar_url</code></td><td>string</td><td>Avatar image URL</td></tr><tr><td><code>user.group_name</code></td><td>string</td><td>User&#39;s group/role name</td></tr><tr><td><code>user.group_image_url</code></td><td>string</td><td>Group banner image URL (may be empty)</td></tr><tr><td><code>user.custom_title</code></td><td>string</td><td>Custom title or rank name</td></tr><tr><td><code>user.rank</code></td><td>string</td><td>Rank name</td></tr><tr><td><code>user.num_posts</code></td><td>string</td><td>Formatted post count</td></tr><tr><td><code>user.num_topics</code></td><td>string</td><td>Formatted topic count</td></tr><tr><td><code>user.joined</code></td><td>string</td><td>Short join date (e.g., &quot;15th Mar 24&quot;)</td></tr><tr><td><code>user.joined_long</code></td><td>string</td><td>Long join date (e.g., &quot;Mar 2024&quot;)</td></tr><tr><td><code>user.reputation</code></td><td>string</td><td>Reaction/reputation score</td></tr><tr><td><code>user.location</code></td><td>string</td><td>User location (may be empty)</td></tr><tr><td><code>user.is_online</code></td><td>boolean</td><td>Whether user is currently online</td></tr><tr><td><code>user.last_active</code></td><td>string</td><td>Last activity (e.g., &quot;2 hours ago&quot;)</td></tr><tr><td><code>user.profile_url</code></td><td>string</td><td>Profile page URL</td></tr><tr><td><code>user.custom_fields</code></td><td>array</td><td>Custom profile fields</td></tr><tr><td><code>user.custom_fields[].label</code></td><td>string</td><td>Field label</td></tr><tr><td><code>user.custom_fields[].value</code></td><td>string</td><td>Field value</td></tr><tr><td><code>user.achievements</code></td><td>array</td><td>Showcased achievements</td></tr><tr><td><code>user.achievements[].name</code></td><td>string</td><td>Achievement name</td></tr><tr><td><code>user.achievements[].icon</code></td><td>string</td><td>Achievement icon URL</td></tr><tr><td><code>user.achievements[].tier</code></td><td>string</td><td>Tier: bronze, silver, or gold</td></tr></tbody></table><h3 id="example-reply" tabindex="-1">Example: Reply <a class="header-anchor" href="#example-reply" aria-label="Permalink to &quot;Example: Reply&quot;">​</a></h3><div class="language-html"><button title="Copy Code" class="copy"></button><span class="lang">html</span><pre class="shiki material-theme-palenight"><code><span class="line"><span style="color:#89DDFF;">&lt;</span><span style="color:#F07178;">div</span><span style="color:#89DDFF;"> </span><span style="color:#C792EA;">style</span><span style="color:#89DDFF;">=</span><span style="color:#89DDFF;">&quot;</span><span style="color:#C3E88D;">display: flex; border-bottom: 2px solid #e2e8f0; margin-bottom: 1rem;</span><span style="color:#89DDFF;">&quot;</span><span style="color:#89DDFF;">&gt;</span></span>
<span class="line"><span style="color:#A6ACCD;">    </span><span style="color:#676E95;font-style:italic;">&lt;!-- User sidebar --&gt;</span></span>
<span class="line"><span style="color:#A6ACCD;">    </span><span style="color:#89DDFF;">&lt;</span><span style="color:#F07178;">div</span><span style="color:#89DDFF;"> </span><span style="color:#C792EA;">style</span><span style="color:#89DDFF;">=</span><span style="color:#89DDFF;">&quot;</span><span style="color:#C3E88D;">width: 180px; padding: 1rem; text-align: center; border-right: 1px solid #e2e8f0;</span><span style="color:#89DDFF;">&quot;</span><span style="color:#89DDFF;">&gt;</span></span>
<span class="line"><span style="color:#A6ACCD;">        </span><span style="color:#89DDFF;">&lt;</span><span style="color:#F07178;">a</span><span style="color:#89DDFF;"> </span><span style="color:#C792EA;">href</span><span style="color:#89DDFF;">=</span><span style="color:#89DDFF;">&quot;</span><span style="color:#C3E88D;">{{ user.profile_url }}</span><span style="color:#89DDFF;">&quot;</span><span style="color:#89DDFF;">&gt;</span></span>
<span class="line"><span style="color:#A6ACCD;">            </span><span style="color:#89DDFF;">&lt;</span><span style="color:#F07178;">img</span><span style="color:#89DDFF;"> </span><span style="color:#C792EA;">src</span><span style="color:#89DDFF;">=</span><span style="color:#89DDFF;">&quot;</span><span style="color:#C3E88D;">{{ user.avatar_url }}</span><span style="color:#89DDFF;">&quot;</span><span style="color:#89DDFF;"> </span><span style="color:#C792EA;">alt</span><span style="color:#89DDFF;">=</span><span style="color:#89DDFF;">&quot;</span><span style="color:#C3E88D;">{{ user.username }}</span><span style="color:#89DDFF;">&quot;</span></span>
<span class="line"><span style="color:#89DDFF;">                 </span><span style="color:#C792EA;">style</span><span style="color:#89DDFF;">=</span><span style="color:#89DDFF;">&quot;</span><span style="color:#C3E88D;">width: 80px; height: 80px; border-radius: 50%; margin: 0 auto;</span><span style="color:#89DDFF;">&quot;</span><span style="color:#89DDFF;"> /&gt;</span></span>
<span class="line"><span style="color:#A6ACCD;">        </span><span style="color:#89DDFF;">&lt;/</span><span style="color:#F07178;">a</span><span style="color:#89DDFF;">&gt;</span></span>
<span class="line"><span style="color:#A6ACCD;">        </span><span style="color:#89DDFF;">&lt;</span><span style="color:#F07178;">div</span><span style="color:#89DDFF;"> </span><span style="color:#C792EA;">style</span><span style="color:#89DDFF;">=</span><span style="color:#89DDFF;">&quot;</span><span style="color:#C3E88D;">font-weight: bold; margin-top: 0.5rem;</span><span style="color:#89DDFF;">&quot;</span><span style="color:#89DDFF;">&gt;</span><span style="color:#A6ACCD;">{{ user.username }}</span><span style="color:#89DDFF;">&lt;/</span><span style="color:#F07178;">div</span><span style="color:#89DDFF;">&gt;</span></span>
<span class="line"><span style="color:#A6ACCD;">        </span><span style="color:#89DDFF;">&lt;</span><span style="color:#F07178;">div</span><span style="color:#89DDFF;"> </span><span style="color:#C792EA;">style</span><span style="color:#89DDFF;">=</span><span style="color:#89DDFF;">&quot;</span><span style="color:#C3E88D;">font-size: 0.8rem; color: #64748b;</span><span style="color:#89DDFF;">&quot;</span><span style="color:#89DDFF;">&gt;</span><span style="color:#A6ACCD;">{{ user.group_name }}</span><span style="color:#89DDFF;">&lt;/</span><span style="color:#F07178;">div</span><span style="color:#89DDFF;">&gt;</span></span>
<span class="line"><span style="color:#A6ACCD;">        </span><span style="color:#89DDFF;">&lt;</span><span style="color:#F07178;">div</span><span style="color:#89DDFF;"> </span><span style="color:#C792EA;">style</span><span style="color:#89DDFF;">=</span><span style="color:#89DDFF;">&quot;</span><span style="color:#C3E88D;">font-size: 0.75rem; color: #94a3b8; margin-top: 0.5rem;</span><span style="color:#89DDFF;">&quot;</span><span style="color:#89DDFF;">&gt;</span></span>
<span class="line"><span style="color:#A6ACCD;">            Posts: {{ user.num_posts }}</span><span style="color:#89DDFF;">&lt;</span><span style="color:#F07178;">br</span><span style="color:#89DDFF;"> /&gt;</span></span>
<span class="line"><span style="color:#A6ACCD;">            Joined: {{ user.joined }}</span></span>
<span class="line"><span style="color:#A6ACCD;">        </span><span style="color:#89DDFF;">&lt;/</span><span style="color:#F07178;">div</span><span style="color:#89DDFF;">&gt;</span></span>
<span class="line"><span style="color:#A6ACCD;">        {{#if user.is_online}}</span></span>
<span class="line"><span style="color:#A6ACCD;">            </span><span style="color:#89DDFF;">&lt;</span><span style="color:#F07178;">span</span><span style="color:#89DDFF;"> </span><span style="color:#C792EA;">style</span><span style="color:#89DDFF;">=</span><span style="color:#89DDFF;">&quot;</span><span style="color:#C3E88D;">color: #22c55e; font-size: 0.75rem;</span><span style="color:#89DDFF;">&quot;</span><span style="color:#89DDFF;">&gt;</span><span style="color:#A6ACCD;">● Online</span><span style="color:#89DDFF;">&lt;/</span><span style="color:#F07178;">span</span><span style="color:#89DDFF;">&gt;</span></span>
<span class="line"><span style="color:#A6ACCD;">        {{/if}}</span></span>
<span class="line"><span style="color:#A6ACCD;">    </span><span style="color:#89DDFF;">&lt;/</span><span style="color:#F07178;">div</span><span style="color:#89DDFF;">&gt;</span></span>
<span class="line"></span>
<span class="line"><span style="color:#A6ACCD;">    </span><span style="color:#676E95;font-style:italic;">&lt;!-- Post content --&gt;</span></span>
<span class="line"><span style="color:#A6ACCD;">    </span><span style="color:#89DDFF;">&lt;</span><span style="color:#F07178;">div</span><span style="color:#89DDFF;"> </span><span style="color:#C792EA;">style</span><span style="color:#89DDFF;">=</span><span style="color:#89DDFF;">&quot;</span><span style="color:#C3E88D;">flex: 1; display: flex; flex-direction: column;</span><span style="color:#89DDFF;">&quot;</span><span style="color:#89DDFF;">&gt;</span></span>
<span class="line"><span style="color:#A6ACCD;">        </span><span style="color:#89DDFF;">&lt;</span><span style="color:#F07178;">div</span><span style="color:#89DDFF;"> </span><span style="color:#C792EA;">style</span><span style="color:#89DDFF;">=</span><span style="color:#89DDFF;">&quot;</span><span style="color:#C3E88D;">padding: 0.5rem 1rem; font-size: 0.8rem; color: #94a3b8; border-bottom: 1px solid #f1f5f9;</span><span style="color:#89DDFF;">&quot;</span><span style="color:#89DDFF;">&gt;</span></span>
<span class="line"><span style="color:#A6ACCD;">            #{{ reply.number }} · {{ reply.created_at }}</span></span>
<span class="line"><span style="color:#A6ACCD;">        </span><span style="color:#89DDFF;">&lt;/</span><span style="color:#F07178;">div</span><span style="color:#89DDFF;">&gt;</span></span>
<span class="line"><span style="color:#A6ACCD;">        </span><span style="color:#89DDFF;">&lt;</span><span style="color:#F07178;">div</span><span style="color:#89DDFF;"> </span><span style="color:#C792EA;">style</span><span style="color:#89DDFF;">=</span><span style="color:#89DDFF;">&quot;</span><span style="color:#C3E88D;">padding: 1rem; flex: 1;</span><span style="color:#89DDFF;">&quot;</span><span style="color:#89DDFF;">&gt;</span></span>
<span class="line"><span style="color:#A6ACCD;">            {{ reply.content }}</span></span>
<span class="line"><span style="color:#A6ACCD;">        </span><span style="color:#89DDFF;">&lt;/</span><span style="color:#F07178;">div</span><span style="color:#89DDFF;">&gt;</span></span>
<span class="line"><span style="color:#A6ACCD;">        {{#if reply.attachments}}</span></span>
<span class="line"><span style="color:#A6ACCD;">            </span><span style="color:#89DDFF;">&lt;</span><span style="color:#F07178;">div</span><span style="color:#89DDFF;"> </span><span style="color:#C792EA;">style</span><span style="color:#89DDFF;">=</span><span style="color:#89DDFF;">&quot;</span><span style="color:#C3E88D;">padding: 0.75rem 1rem; border-top: 1px solid #e2e8f0; font-size: 0.875rem;</span><span style="color:#89DDFF;">&quot;</span><span style="color:#89DDFF;">&gt;</span></span>
<span class="line"><span style="color:#A6ACCD;">                </span><span style="color:#89DDFF;">&lt;</span><span style="color:#F07178;">strong</span><span style="color:#89DDFF;">&gt;</span><span style="color:#A6ACCD;">Attachments:</span><span style="color:#89DDFF;">&lt;/</span><span style="color:#F07178;">strong</span><span style="color:#89DDFF;">&gt;</span></span>
<span class="line"><span style="color:#A6ACCD;">                {{#each reply.attachments}}</span></span>
<span class="line"><span style="color:#A6ACCD;">                    {{#if this.is_image}}</span></span>
<span class="line"><span style="color:#A6ACCD;">                        </span><span style="color:#89DDFF;">&lt;</span><span style="color:#F07178;">img</span><span style="color:#89DDFF;"> </span><span style="color:#C792EA;">src</span><span style="color:#89DDFF;">=</span><span style="color:#89DDFF;">&quot;</span><span style="color:#C3E88D;">{{ this.url }}</span><span style="color:#89DDFF;">&quot;</span><span style="color:#89DDFF;"> </span><span style="color:#C792EA;">alt</span><span style="color:#89DDFF;">=</span><span style="color:#89DDFF;">&quot;</span><span style="color:#C3E88D;">{{ this.filename }}</span><span style="color:#89DDFF;">&quot;</span><span style="color:#89DDFF;"> </span><span style="color:#C792EA;">style</span><span style="color:#89DDFF;">=</span><span style="color:#89DDFF;">&quot;</span><span style="color:#C3E88D;">max-width: 200px; margin: 0.5rem 0;</span><span style="color:#89DDFF;">&quot;</span><span style="color:#89DDFF;"> /&gt;</span></span>
<span class="line"><span style="color:#A6ACCD;">                    {{/if}}</span></span>
<span class="line"><span style="color:#A6ACCD;">                    {{#unless this.is_image}}</span></span>
<span class="line"><span style="color:#A6ACCD;">                        </span><span style="color:#89DDFF;">&lt;</span><span style="color:#F07178;">a</span><span style="color:#89DDFF;"> </span><span style="color:#C792EA;">href</span><span style="color:#89DDFF;">=</span><span style="color:#89DDFF;">&quot;</span><span style="color:#C3E88D;">{{ this.url }}</span><span style="color:#89DDFF;">&quot;</span><span style="color:#89DDFF;">&gt;</span><span style="color:#A6ACCD;">{{ this.filename }} ({{ this.size }})</span><span style="color:#89DDFF;">&lt;/</span><span style="color:#F07178;">a</span><span style="color:#89DDFF;">&gt;</span></span>
<span class="line"><span style="color:#A6ACCD;">                    {{/unless}}</span></span>
<span class="line"><span style="color:#A6ACCD;">                {{/each}}</span></span>
<span class="line"><span style="color:#A6ACCD;">            </span><span style="color:#89DDFF;">&lt;/</span><span style="color:#F07178;">div</span><span style="color:#89DDFF;">&gt;</span></span>
<span class="line"><span style="color:#A6ACCD;">        {{/if}}</span></span>
<span class="line"><span style="color:#A6ACCD;">    </span><span style="color:#89DDFF;">&lt;/</span><span style="color:#F07178;">div</span><span style="color:#89DDFF;">&gt;</span></span>
<span class="line"><span style="color:#89DDFF;">&lt;/</span><span style="color:#F07178;">div</span><span style="color:#89DDFF;">&gt;</span></span></code></pre></div><hr><h2 id="category-template" tabindex="-1">Category Template <a class="header-anchor" href="#category-template" aria-label="Permalink to &quot;Category Template&quot;">​</a></h2><p>Customizes the category wrapper on the board index. Each category contains its forum rows.</p><h3 id="available-variables-3" tabindex="-1">Available Variables <a class="header-anchor" href="#available-variables-3" aria-label="Permalink to &quot;Available Variables&quot;">​</a></h3><table><thead><tr><th>Variable</th><th>Type</th><th>Description</th></tr></thead><tbody><tr><td><code>category.id</code></td><td>number</td><td>Category (forum) ID</td></tr><tr><td><code>category.name</code></td><td>string</td><td>Category name</td></tr><tr><td><code>category.url</code></td><td>string</td><td>Category URL</td></tr><tr><td><code>category.forums</code></td><td>array</td><td>Forums in this category</td></tr><tr><td><code>category.forums[].name</code></td><td>string</td><td>Forum name</td></tr><tr><td><code>category.forums[].url</code></td><td>string</td><td>Forum URL</td></tr><tr><td><code>category.forums[].is_read</code></td><td>boolean</td><td>Whether forum is read</td></tr></tbody></table><h3 id="example-category" tabindex="-1">Example: Category <a class="header-anchor" href="#example-category" aria-label="Permalink to &quot;Example: Category&quot;">​</a></h3><div class="language-html"><button title="Copy Code" class="copy"></button><span class="lang">html</span><pre class="shiki material-theme-palenight"><code><span class="line"><span style="color:#89DDFF;">&lt;</span><span style="color:#F07178;">div</span><span style="color:#89DDFF;"> </span><span style="color:#C792EA;">style</span><span style="color:#89DDFF;">=</span><span style="color:#89DDFF;">&quot;</span><span style="color:#C3E88D;">margin-bottom: 2rem; border: 1px solid #ccdbf1; border-radius: 0.25rem; overflow: hidden;</span><span style="color:#89DDFF;">&quot;</span><span style="color:#89DDFF;">&gt;</span></span>
<span class="line"><span style="color:#A6ACCD;">    </span><span style="color:#89DDFF;">&lt;</span><span style="color:#F07178;">div</span><span style="color:#89DDFF;"> </span><span style="color:#C792EA;">style</span><span style="color:#89DDFF;">=</span><span style="color:#89DDFF;">&quot;</span><span style="color:#C3E88D;">background: linear-gradient(to bottom, #4c6ec4, #6087d1); color: white; padding: 0.75rem 1rem;</span><span style="color:#89DDFF;">&quot;</span><span style="color:#89DDFF;">&gt;</span></span>
<span class="line"><span style="color:#A6ACCD;">        </span><span style="color:#89DDFF;">&lt;</span><span style="color:#F07178;">a</span><span style="color:#89DDFF;"> </span><span style="color:#C792EA;">href</span><span style="color:#89DDFF;">=</span><span style="color:#89DDFF;">&quot;</span><span style="color:#C3E88D;">{{ category.url }}</span><span style="color:#89DDFF;">&quot;</span><span style="color:#89DDFF;"> </span><span style="color:#C792EA;">style</span><span style="color:#89DDFF;">=</span><span style="color:#89DDFF;">&quot;</span><span style="color:#C3E88D;">color: white; font-weight: bold; font-size: 1.1rem;</span><span style="color:#89DDFF;">&quot;</span><span style="color:#89DDFF;">&gt;</span></span>
<span class="line"><span style="color:#A6ACCD;">            {{ category.name }}</span></span>
<span class="line"><span style="color:#A6ACCD;">        </span><span style="color:#89DDFF;">&lt;/</span><span style="color:#F07178;">a</span><span style="color:#89DDFF;">&gt;</span></span>
<span class="line"><span style="color:#A6ACCD;">    </span><span style="color:#89DDFF;">&lt;/</span><span style="color:#F07178;">div</span><span style="color:#89DDFF;">&gt;</span></span>
<span class="line"><span style="color:#A6ACCD;">    </span><span style="color:#676E95;font-style:italic;">&lt;!-- Forum rows are automatically rendered inside the category --&gt;</span></span>
<span class="line"><span style="color:#89DDFF;">&lt;/</span><span style="color:#F07178;">div</span><span style="color:#89DDFF;">&gt;</span></span></code></pre></div><div class="warning custom-block"><p class="custom-block-title">WARNING</p><p>The category template wraps around the forum rows. The individual forum rows within the category are rendered using the <strong>Forum Row Template</strong> (if set) or the default layout.</p></div><hr><h2 id="mini-profile-profile-templates" tabindex="-1">Mini Profile &amp; Profile Templates <a class="header-anchor" href="#mini-profile-profile-templates" aria-label="Permalink to &quot;Mini Profile &amp; Profile Templates&quot;">​</a></h2><p>In addition to the four main layout templates, you can also customize:</p><h3 id="mini-profile-template" tabindex="-1">Mini Profile Template <a class="header-anchor" href="#mini-profile-template" aria-label="Permalink to &quot;Mini Profile Template&quot;">​</a></h3><p>The user info card shown alongside each post (in the user sidebar area of replies). Uses the same <strong>user variables</strong> listed in the Reply Template section above.</p><h3 id="profile-template" tabindex="-1">Profile Template <a class="header-anchor" href="#profile-template" aria-label="Permalink to &quot;Profile Template&quot;">​</a></h3><p>The user profile page header. Uses all <strong>user variables</strong> plus:</p><table><thead><tr><th>Variable</th><th>Type</th><th>Description</th></tr></thead><tbody><tr><td><code>user.best_answers</code></td><td>number</td><td>Count of best/accepted answers</td></tr></tbody></table><hr><h2 id="tips-best-practices" tabindex="-1">Tips &amp; Best Practices <a class="header-anchor" href="#tips-best-practices" aria-label="Permalink to &quot;Tips &amp; Best Practices&quot;">​</a></h2><h3 id="use-inline-styles-for-custom-templates" tabindex="-1">Use Inline Styles for Custom Templates <a class="header-anchor" href="#use-inline-styles-for-custom-templates" aria-label="Permalink to &quot;Use Inline Styles for Custom Templates&quot;">​</a></h3><p>Since custom templates bypass the base CSS classes, use inline styles or define your own classes in the theme&#39;s Custom CSS:</p><div class="language-html"><button title="Copy Code" class="copy"></button><span class="lang">html</span><pre class="shiki material-theme-palenight"><code><span class="line"><span style="color:#676E95;font-style:italic;">&lt;!-- Option 1: Inline styles --&gt;</span></span>
<span class="line"><span style="color:#89DDFF;">&lt;</span><span style="color:#F07178;">div</span><span style="color:#89DDFF;"> </span><span style="color:#C792EA;">style</span><span style="color:#89DDFF;">=</span><span style="color:#89DDFF;">&quot;</span><span style="color:#C3E88D;">padding: 1rem; background: #f8fafd;</span><span style="color:#89DDFF;">&quot;</span><span style="color:#89DDFF;">&gt;</span><span style="color:#A6ACCD;">{{ forum.name }}</span><span style="color:#89DDFF;">&lt;/</span><span style="color:#F07178;">div</span><span style="color:#89DDFF;">&gt;</span></span>
<span class="line"></span>
<span class="line"><span style="color:#676E95;font-style:italic;">&lt;!-- Option 2: Custom class + theme CSS --&gt;</span></span>
<span class="line"><span style="color:#89DDFF;">&lt;</span><span style="color:#F07178;">div</span><span style="color:#89DDFF;"> </span><span style="color:#C792EA;">class</span><span style="color:#89DDFF;">=</span><span style="color:#89DDFF;">&quot;</span><span style="color:#C3E88D;">my-forum-row</span><span style="color:#89DDFF;">&quot;</span><span style="color:#89DDFF;">&gt;</span><span style="color:#A6ACCD;">{{ forum.name }}</span><span style="color:#89DDFF;">&lt;/</span><span style="color:#F07178;">div</span><span style="color:#89DDFF;">&gt;</span></span></code></pre></div><div class="language-css"><button title="Copy Code" class="copy"></button><span class="lang">css</span><pre class="shiki material-theme-palenight"><code><span class="line"><span style="color:#676E95;font-style:italic;">/* In your theme&#39;s Custom CSS */</span></span>
<span class="line"><span style="color:#89DDFF;">.</span><span style="color:#FFCB6B;">my-forum-row</span><span style="color:#A6ACCD;"> </span><span style="color:#89DDFF;">{</span></span>
<span class="line"><span style="color:#A6ACCD;">    </span><span style="color:#B2CCD6;">padding</span><span style="color:#89DDFF;">:</span><span style="color:#A6ACCD;"> </span><span style="color:#F78C6C;">1rem</span><span style="color:#89DDFF;">;</span></span>
<span class="line"><span style="color:#A6ACCD;">    </span><span style="color:#B2CCD6;">background</span><span style="color:#89DDFF;">:</span><span style="color:#A6ACCD;"> </span><span style="color:#82AAFF;">var</span><span style="color:#89DDFF;">(</span><span style="color:#A6ACCD;">--fs-forum-bg</span><span style="color:#89DDFF;">);</span></span>
<span class="line"><span style="color:#89DDFF;">}</span></span></code></pre></div><h3 id="use-css-variables-for-theme-consistency" tabindex="-1">Use CSS Variables for Theme Consistency <a class="header-anchor" href="#use-css-variables-for-theme-consistency" aria-label="Permalink to &quot;Use CSS Variables for Theme Consistency&quot;">​</a></h3><p>Reference the theme&#39;s CSS custom properties to ensure your templates respect the user&#39;s color settings:</p><div class="language-html"><button title="Copy Code" class="copy"></button><span class="lang">html</span><pre class="shiki material-theme-palenight"><code><span class="line"><span style="color:#89DDFF;">&lt;</span><span style="color:#F07178;">div</span><span style="color:#89DDFF;"> </span><span style="color:#C792EA;">style</span><span style="color:#89DDFF;">=</span><span style="color:#89DDFF;">&quot;</span><span style="color:#C3E88D;">background: var(--fs-forum-bg); color: var(--fs-body-color); border-color: var(--fs-forum-divider);</span><span style="color:#89DDFF;">&quot;</span><span style="color:#89DDFF;">&gt;</span></span>
<span class="line"><span style="color:#A6ACCD;">    {{ forum.name }}</span></span>
<span class="line"><span style="color:#89DDFF;">&lt;/</span><span style="color:#F07178;">div</span><span style="color:#89DDFF;">&gt;</span></span></code></pre></div><h3 id="dark-mode-compatibility" tabindex="-1">Dark Mode Compatibility <a class="header-anchor" href="#dark-mode-compatibility" aria-label="Permalink to &quot;Dark Mode Compatibility&quot;">​</a></h3><p>When using inline styles, you can&#39;t easily target dark mode. For dark mode support, use CSS custom properties (which automatically switch) or define classes in your Custom CSS with <code>.dark</code> prefixes:</p><div class="language-css"><button title="Copy Code" class="copy"></button><span class="lang">css</span><pre class="shiki material-theme-palenight"><code><span class="line"><span style="color:#89DDFF;">.</span><span style="color:#FFCB6B;">my-forum-link</span><span style="color:#A6ACCD;"> </span><span style="color:#89DDFF;">{</span><span style="color:#A6ACCD;"> </span><span style="color:#B2CCD6;">color</span><span style="color:#89DDFF;">:</span><span style="color:#A6ACCD;"> </span><span style="color:#89DDFF;">#</span><span style="color:#A6ACCD;">4059ad</span><span style="color:#89DDFF;">;</span><span style="color:#A6ACCD;"> </span><span style="color:#89DDFF;">}</span></span>
<span class="line"><span style="color:#89DDFF;">.</span><span style="color:#FFCB6B;">dark</span><span style="color:#A6ACCD;"> </span><span style="color:#89DDFF;">.</span><span style="color:#FFCB6B;">my-forum-link</span><span style="color:#A6ACCD;"> </span><span style="color:#89DDFF;">{</span><span style="color:#A6ACCD;"> </span><span style="color:#B2CCD6;">color</span><span style="color:#89DDFF;">:</span><span style="color:#A6ACCD;"> </span><span style="color:#89DDFF;">#</span><span style="color:#A6ACCD;">7fa5db</span><span style="color:#89DDFF;">;</span><span style="color:#A6ACCD;"> </span><span style="color:#89DDFF;">}</span></span></code></pre></div><h3 id="resetting-to-default" tabindex="-1">Resetting to Default <a class="header-anchor" href="#resetting-to-default" aria-label="Permalink to &quot;Resetting to Default&quot;">​</a></h3><p>To remove a custom template and return to the default layout, clear the template content in the admin editor and save.</p><h3 id="template-sanitization" tabindex="-1">Template Sanitization <a class="header-anchor" href="#template-sanitization" aria-label="Permalink to &quot;Template Sanitization&quot;">​</a></h3><p>Templates are sanitized on save using HTML Purifier. Potentially dangerous HTML (e.g., <code>&lt;script&gt;</code> tags, event handlers) will be stripped. Template variables (<code>{{ }}</code>, <code>{{#if}}</code>, etc.) are preserved through sanitization.</p>`,81),e=[l];function p(r,c,d,i,D,y){return a(),t("div",null,e)}const m=s(n,[["render",p]]);export{u as __pageData,m as default};
